// Pattern 4 — JWT body-tunnel (CLAUDE.md §Pattern 4)
// Browser CORS blocks Authorization headers on cross-origin requests.
// Frontend embeds raw JWT in body.jwt; n8n normalises to Bearer format for db-api calls.
const item    = $input.first().json;
const headers = item.headers || {};

// Normalise body: n8n stores text/plain requests as a raw string (or as
// numbered-char keys when the body is very large). Parse both cases so
// body.jwt is accessible regardless of the request Content-Type.
let body = item.body || {};
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) { body = {}; }
} else if (typeof body === 'object' && body !== null
           && Object.keys(body).length > 0
           && Object.keys(body).every(k => !isNaN(k))) {
  // Numbered-char-key encoding — reconstruct and parse
  try { body = JSON.parse(Object.values(body).join('')); } catch(e) { body = {}; }
}

const rawToken = headers.authorization
              || headers.Authorization
              || body.jwt
              || '';
const auth = rawToken.startsWith('Bearer ')
  ? rawToken
  : (rawToken ? 'Bearer ' + rawToken : '');
return [{ json: { ...item, _auth: auth } }];

// Parse incoming payload (handles chunked or direct JSON)
const items = $input.all();
let rawData = items[0]?.json || {};
let finalResult = {};

try {
  if (rawData.hasOwnProperty('0')) {
    const combinedString = Object.values(rawData).join('');
    finalResult = JSON.parse(combinedString);
  } else if (rawData.body && typeof rawData.body === 'object') {
    finalResult = rawData.body;
  } else if (typeof rawData.body === 'string') {
    finalResult = JSON.parse(rawData.body);
  } else {
    finalResult = rawData;
  }
} catch (e) {
  finalResult = rawData;
  finalResult._error = 'Parsing failed: ' + e.message;
}

const monthlyFee = parseFloat(
  finalResult.monthly_fee ||
  finalResult.agreed_price ||
  finalResult.monthly_rate ||
  '0'
) || 0;

const output = {
  ...finalResult,
  tenant_id:         parseInt(finalResult.tenant_id || 1001),
  day_of_week:       parseInt(finalResult.day_of_week ?? -1),
  payment_amount:    parseFloat(finalResult.payment_amount || '0') || 0,
  rate_per_session:  parseFloat(finalResult.rate_per_session || '0') || 0,
  monthly_fee:       monthlyFee,
  agreed_price:      monthlyFee,
  total_cycles:      parseInt(finalResult.total_cycles || '0') || 0,
  remaining_cycles:  parseInt(finalResult.remaining_cycles || finalResult.total_cycles || '0') || 0,
  billing_day:       parseInt(finalResult.billing_day || '1') || 1,
  billing_type:      finalResult.billing_type || 'monthly',
  interaction_type:  finalResult.interaction_type || 'RECURRING_CONTRACT_CREATED',
  contract_notes:    finalResult.contract_notes || '',
  status:            finalResult.status || 'confirmed',
  booking_source:    finalResult.booking_source || 'calendar_recurring',
  _debug_parsed:     true
};

return [{ json: output }];

