const wb = $('Parse: Input').first().json;

const specificDates = (wb.specific_dates || '').trim();
const ratePerSession = parseFloat(wb.rate_per_session || '0') || 0;
const billingType    = (wb.billing_type || 'monthly').toLowerCase();
const paymentTiming  = wb.payment_timing || 'in_advance';

if (!specificDates) {
  return [{ json: { error: 'Missing specific_dates', date_count: 0, dates: '', payment_timing: paymentTiming } }];
}

const dates = specificDates.split(',').map(d => d.trim()).filter(d => /^\d{4}-\d{2}-\d{2}$/.test(d)).sort();

const firstDate = dates[0] || '';
const lastDate  = dates[dates.length - 1] || '';

let firstPeriodEnd = '';
if (firstDate) {
  const d = new Date(firstDate + 'T12:00:00');
  d.setDate(d.getDate() + 27);
  firstPeriodEnd = d.getFullYear() + '-'
    + String(d.getMonth() + 1).padStart(2, '0') + '-'
    + String(d.getDate()).padStart(2, '0');
}

const cyclePrice = parseFloat(wb.monthly_fee || wb.agreed_price || '0') || ratePerSession * 4;

return [{ json: {
  dates:          dates.join(','),
  date_count:     dates.length,
  payment_timing: paymentTiming,
  billing_type:   billingType,
  first_period_start: firstDate,
  first_period_end:   firstPeriodEnd,
  first_month_amount: cyclePrice.toFixed(2),
  monthly_periods_csv:  firstDate,
  monthly_ends_csv:     firstPeriodEnd,
  monthly_amounts_csv:  cyclePrice.toFixed(2),
  monthly_sessions_csv: String(dates.length),
  monthly_count:        1,
  period_start:         firstDate,
  period_end:           firstPeriodEnd
} }];

// Phase 2: customer data comes from HTTP response, not Postgres node
const wb         = $('Parse: Input').first().json;
const upsertResp = $('HTTP: POST /recurring/upsert-customer').first().json;
const dateGen    = $('Code: Generate Dates').first().json;

// fullResponse:true wraps as { statusCode, headers, body }.
// body may be a parsed object or a JSON string — normalise both.
let upsertBody = upsertResp.body;
if (typeof upsertBody === 'string') {
  try { upsertBody = JSON.parse(upsertBody); } catch(e) { upsertBody = {}; }
}
const httpStatus = upsertResp.statusCode;
if (httpStatus && httpStatus !== 200 && httpStatus !== 201) {
  throw new Error(`upsert-customer HTTP ${httpStatus}: ${JSON.stringify(upsertBody)}`);
}

// Defensive fallback: body.data → body → root (guards against minor API shape changes)
const customerRow = upsertBody?.data || upsertBody || {};
const customer_id = customerRow?.customer_id || customerRow?.id;

const room_id   = wb?.room_id;
const tenant_id = wb?.tenant_id;

if (!customer_id) {
  throw new Error(`upsert-customer did not return a customer_id. HTTP ${httpStatus}, body: ${JSON.stringify(upsertBody)}`);
}
if (!room_id || !tenant_id) {
  throw new Error(`Validation Error: Missing room_id or tenant_id. Room: ${room_id}, Tenant: ${tenant_id}`);
}
if (!dateGen.dates || dateGen.date_count === 0) {
  throw new Error('Validation Error: No dates found in specific_dates.');
}

// Compute paid_sessions_count — how many leading sessions are covered by the upfront payment.
// Floor division: payment_amount / rate_per_session, clamped to [0, date_count].
const paymentAmount  = parseFloat(wb.payment_amount || '0') || 0;
const ratePerSession = parseFloat(wb.rate_per_session || '0') || 0;
const paymentType    = (wb.payment_type || 'none').toLowerCase();
const paid_sessions_count = (paymentType !== 'none' && paymentAmount > 0 && ratePerSession > 0)
  ? Math.min(dateGen.date_count, Math.floor(paymentAmount / ratePerSession))
  : 0;

return [{
  json: {
    customer_id,
    room_id,
    tenant_id,
    dates: dateGen.dates,
    date_count: dateGen.date_count,
    first_month_amount: dateGen.first_month_amount,
    customer_name:       customerRow.full_name || wb.customer_name,
    customer_email:      customerRow.email     || wb.customer_email || '',
    paid_sessions_count
  }
}];

// Phase 2: clashed_dates comes from HTTP response body
const validate = $('Code: Validate').first().json;
const allDates  = (validate.dates || '').split(',').filter(Boolean).sort();
const httpResp  = $input.first().json;
const clashData = httpResp.body?.data || httpResp;
const clashed   = new Set((clashData.clashed_dates || []).map(d => String(d).trim().slice(0,10)));

if (clashed.size === 0) {
  return [{ json: {
    filtered_dates: validate.dates || '',
    dates_count: allDates.length,
    has_conflict: false,
    blocked: false,
    warning: null
  }}];
}

const sortedClashed = [...clashed].sort();
const firstConflict = sortedClashed[0];
const safeDates     = allDates.filter(d => d < firstConflict);

const fmtDate = d => {
  const dt = new Date(d + 'T12:00:00');
  return dt.toLocaleDateString('en-GB', {day:'numeric', month:'long', year:'numeric'});
};

if (safeDates.length === 0) {
  return [{ json: {
    filtered_dates: '',
    dates_count: 0,
    has_conflict: true,
    blocked: true,
    first_conflict_date: firstConflict,
    warning: 'The first session date (' + fmtDate(firstConflict) + ') is already booked for this room at this time. Please choose a different start date or room.'
  }}];
}

return [{ json: {
  filtered_dates: safeDates.join(','),
  dates_count: safeDates.length,
  has_conflict: true,
  blocked: false,
  first_conflict_date: firstConflict,
  clashed_count: clashed.size,
  warning: 'Recurring series created for ' + safeDates.length + ' session(s) up to ' + fmtDate(safeDates[safeDates.length-1]) + '. Bookings stop before ' + fmtDate(firstConflict) + ' — that date is already taken by an existing booking.'
}}];

